<!DOCTYPE html>
<html>
    <head>
        <title>Reduced Motion Toggle</title>
        <link href='https://cdn.jsdelivr.net/npm/tailwindcss@2.2.19/dist/tailwind.min.css' rel='stylesheet'>
    </head>
    <body>
        <button id='reduced-motion-toggle' class='px-4 py-2 border border-gray-400 rounded-lg'>Reduced Motion Toggle</button>
        <script>
            document.addEventListener('DOMContentLoaded', function() {
                const toggleButton = document.getElementById('reduced-motion-toggle');
                const userPreference = localStorage.getItem('reduced-motion');
                if (userPreference === null) {
                    userPreference = 'enabled';
                }
                toggleButton.textContent = userPreference === 'enabled' ? 'Enable Reduced Motion' : 'Disable Reduced Motion';
                toggleButton.addEventListener('click', function() {
                    const newPreference = userPreference === 'enabled' ? 'disabled' : 'enabled';
                    localStorage.setItem('reduced-motion', newPreference);
                    document.body.classList.toggle('reduced-motion', newPreference === 'enabled');
                    toggleButton.textContent = newPreference === 'enabled' ? 'Enable Reduced Motion' : 'Disable Reduced Motion';
                });
                document.body.classList.toggle('reduced-motion', userPreference === 'enabled');
            });
        </script>
    </body>
</html>
